import React, { useState, useEffect } from 'react';
import UserCard from './components/UserCard';
import Schedule from './components/Schedule';
import UserDetails from './components/UserDetails';
import BottomSheet from './components/BottomSheet';
import { usersData } from './data/usersData';
import { PlusIcon, BoltIcon, PencilIcon, ChevronUpIcon, MagnifyingGlassIcon, PaperAirplaneIcon, PaperClipIcon, LinkIcon, XMarkIcon } from '@heroicons/react/24/outline';

function App() {
  const [rightPanelContent, setRightPanelContent] = useState('schedule');
  const [selectedUser, setSelectedUser] = useState(null);
  const [usersWithIcons, setUsersWithIcons] = useState([]);
  const [isBottomSheetOpen, setIsBottomSheetOpen] = useState(false);
  const [activeTab, setActiveTab] = useState('send');
  const [selectedUsers, setSelectedUsers] = useState([]);
  const [message, setMessage] = useState('');

  // Função para gerar ícones aleatórios
  const generateRandomIcons = () => {
    const allIcons = [
      'https://upload.wikimedia.org/wikipedia/commons/3/33/Figma-logo.svg',
      'https://upload.wikimedia.org/wikipedia/commons/7/7e/Gmail_icon_%282020%29.svg',
      'https://upload.wikimedia.org/wikipedia/commons/9/9b/Google_Meet_icon_%282020%29.svg',
      'https://cdn.worldvectorlogo.com/logos/jira-1.svg',
      'https://upload.wikimedia.org/wikipedia/commons/c/c9/Microsoft_Office_Teams_%282018%E2%80%93present%29.svg',
      'https://www.svgrepo.com/show/353597/confluence.svg',
      'https://www.svgrepo.com/show/354463/trello.svg'
    ];

    // Randomizar quantidade de ícones (0 a 5)
    const iconCount = Math.floor(Math.random() * 6);

    if (iconCount === 0) {
      return [];
    }

    // Embaralhar e pegar a quantidade desejada
    const shuffled = [...allIcons].sort(() => 0.5 - Math.random());
    return shuffled.slice(0, iconCount);
  };

  // Gerar ícones uma única vez no carregamento
  useEffect(() => {
    const usersWithRandomIcons = usersData.map(user => ({
      ...user,
      randomIcons: generateRandomIcons()
    }));
    setUsersWithIcons(usersWithRandomIcons);
  }, []);

  const showUserDetails = (user) => {
    setSelectedUser(user);
    setRightPanelContent('userDetails');
  };

  const showSchedule = () => {
    setSelectedUser(null);
    setRightPanelContent('schedule');
  };

  const toggleUserSelection = (user) => {
    setSelectedUsers(prev => {
      const isSelected = prev.find(u => u.id === user.id);
      if (isSelected) {
        return prev.filter(u => u.id !== user.id);
      } else {
        return [...prev, user];
      }
    });
  };

  const removeSelectedUser = (userId) => {
    setSelectedUsers(prev => prev.filter(u => u.id !== userId));
  };

  const teamMembers = [
    { id: 1, name: 'Brent Short', avatar: 'https://images.unsplash.com/photo-1472099645785-5658abf4ff4e?w=32&h=32&fit=crop&crop=face', status: 'online' },
    { id: 2, name: 'Leo Philips', avatar: 'https://images.unsplash.com/photo-1507003211169-0a1dd7228f2d?w=32&h=32&fit=crop&crop=face', status: 'away' },
    { id: 3, name: 'Charlie Bator', avatar: 'https://images.unsplash.com/photo-1494790108755-2616b612b786?w=32&h=32&fit=crop&crop=face', status: 'online' }
  ];

  return (
    <div className="min-h-screen bg-neutral-800 p-6">
      <div className="flex gap-6 h-screen">
        {/* Primeira coluna: 60px */}
        <div className="flex flex-col gap-4" style={{ width: '60px' }}>
          <div className="bg-gray-400 rounded" style={{ width: '60px', height: '60px' }}></div>
          <div className="bg-gray-400 rounded" style={{ width: '60px', height: '60px' }}></div>
        </div>

        {/* Segunda coluna: 300px */}
        <div className="flex flex-col gap-4" style={{ width: '300px' }}>
          <div className="bg-gray-400 rounded h-64" style={{ width: '300px' }}></div>
          <div className="bg-gray-400 rounded flex-1" style={{ width: '300px' }}></div>
        </div>

        {/* Terceira coluna: flex-1 */}
        <div className="flex-1 flex flex-col gap-6">
          {/* Primeira linha: 3 divs retangulares */}
          <div className="flex gap-4">
            <div className="flex-1 bg-blue-500 rounded-lg h-20"></div>
            <div className="flex-1 bg-green-500 rounded-lg h-20"></div>
            <div className="flex-1 bg-red-500 rounded-lg h-20"></div>
          </div>

          {/* Segunda linha: Grid e coluna direita */}
          <div className="flex gap-6 flex-1 min-h-0">
            {/* Grid de cards */}
            <div className="flex-1 overflow-y-auto">
              <div className="grid gap-4" style={{ gridTemplateColumns: 'repeat(auto-fit, minmax(300px, 1fr))' }}>
                {usersWithIcons.map((user) => (
                  <UserCard 
                    key={user.id} 
                    user={user}
                    onClick={() => showUserDetails(user)} 
                  />
                ))}
              </div>
            </div>

            {/* Coluna direita */}
            <div className="overflow-y-auto" style={{ width: '350px' }}>
              {rightPanelContent === 'schedule' ? (
                <Schedule />
              ) : (
                <UserDetails user={selectedUser} onBack={showSchedule} />
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Floating Action Bar - Nudges */}
      <div className="fixed bottom-0 right-6 z-40">
        <button
          onClick={() => setIsBottomSheetOpen(true)}
          className="flex items-center space-x-3 bg-neutral-900 hover:bg-neutral-800 text-white px-4 py-3 shadow-2xl transition-all duration-200 border border-gray-700"
          style={{ 
            width: '300px',
            borderRadius: '16px 16px 0 0'
          }}
          aria-label="Abrir Nudges"
        >
          {/* Icon with Badge */}
          <div className="relative flex-shrink-0">
            <div className="w-8 h-8 bg-neutral-800 rounded-full flex items-center justify-center">
              <BoltIcon className="h-5 w-5 text-white" />
            </div>
            <div className="absolute -top-1 -right-1 w-4 h-4 bg-red-500 rounded-full flex items-center justify-center">
              <span className="text-xs font-bold text-white">1</span>
            </div>
          </div>

          {/* Title */}
          <span className="text-base font-medium text-white flex-1">Nudges</span>

          {/* Action Icons */}
          <div className="flex items-center space-x-2 flex-shrink-0">
            <div className="p-1.5 text-gray-300 hover:text-white transition-colors">
              <PencilIcon className="h-4 w-4" />
            </div>
            <div className="p-1.5 text-gray-300 hover:text-white transition-colors">
              <ChevronUpIcon className="h-4 w-4" />
            </div>
          </div>
        </button>
      </div>

      {/* Bottom Sheet */}
      <BottomSheet
        isOpen={isBottomSheetOpen}
        onClose={() => setIsBottomSheetOpen(false)}
        title="Nudges"
        maxWidth="400px"
        maxHeight="70vh"
        badgeCount={3}
      >
        <div className="space-y-4">
          <div>
